import { ApiProperty, ApiPropertyOptional } from "@nestjs/swagger";

export class ClientAccountData {
  @ApiProperty({ description: "National ID (CID)", example: "10705001283" })
  national_id!: string;

  @ApiProperty({
    description: "Account number",
    example: "100100366202",
  })
  account_number!: string;

  @ApiProperty({ description: "Citizen country", example: "Bhutan" })
  citizen_country!: string;

  @ApiProperty({ description: "First name", example: "Sangay" })
  first_name!: string;

  @ApiPropertyOptional({ description: "Middle name", nullable: true })
  middle_name?: string | null;

  @ApiProperty({ description: "Last name", example: "Wangdi" })
  last_name!: string;

  @ApiPropertyOptional({ description: "Phone number", example: "17123456" })
  phone_number?: string;
}

export class ClientInquiryResponseDto {
  @ApiProperty({ description: "Response code", example: "0000" })
  response_code!: string;

  @ApiProperty({ description: "Response message", example: "Success" })
  response_message!: string;

  @ApiProperty({
    description: "Response description",
    example: "Record of Customer Details",
  })
  response_description!: string;

  @ApiProperty({
    type: [ClientAccountData],
    description: "Customer account details",
  })
  response_data!: ClientAccountData[];
}
